SELECT id, name, short_name, description, logo_url, official_website, is_985, is_211, is_double_first_class, school_type, province, city FROM university
is_deleted = 0
AND (name LIKE CONCAT('%', #{keyword}, '%') OR short_name LIKE CONCAT('%', #{keyword}, '%'))
AND province = #{province}
AND city = #{city}
ORDER BY id
